func (this *CoinsphCore) ParseTicker(ticker any, optionalArgs ...any) any {
	//
	// publicGetOpenapiQuoteV1Ticker24hr
	//     {
	//         "symbol": "ETHUSDT",
	//         "priceChange": "41.440000000000000000",
	//         "priceChangePercent": "0.0259",
	//         "weightedAvgPrice": "1631.169825783972125436",
	//         "prevClosePrice": "1601.520000000000000000",
	//         "lastPrice": "1642.96",
	//         "lastQty": "0.000001000000000000",
	//         "bidPrice": "1638.790000000000000000",
	//         "bidQty": "0.280075000000000000",
	//         "askPrice": "1647.340000000000000000",
	//         "askQty": "0.165183000000000000",
	//         "openPrice": "1601.52",
	//         "highPrice": "1648.28",
	//         "lowPrice": "1601.52",
	//         "volume": "0.000287",
	//         "quoteVolume": "0.46814574",
	//         "openTime": "1677417000000",
	//         "closeTime": "1677503415200",
	//         "firstId": "1364680572697591809",
	//         "lastId": "1365389809203560449",
	//         "count": "100"
	//     }
	//
	// publicGetOpenapiQuoteV1TickerPrice
	//     { "symbol": "ETHUSDT", "price": "1599.68" }
	//
	// publicGetOpenapiQuoteV1TickerBookTicker
	//     {
	//         "symbol": "ETHUSDT",
	//         "bidPrice": "1596.57",
	//         "bidQty": "0.246405",
	//         "askPrice": "1605.12",
	//         "askQty": "0.242681"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString(ticker, "symbol")
	market = this.SafeMarket(marketId, market)
	var timestamp any = this.SafeInteger(ticker, "closeTime")
	var bid any = this.SafeString(ticker, "bidPrice")
	var ask any = this.SafeString(ticker, "askPrice")
	var bidVolume any = this.SafeString(ticker, "bidQty")
	var askVolume any = this.SafeString(ticker, "askQty")
	var baseVolume any = this.SafeString(ticker, "volume")
	var quoteVolume any = this.SafeString(ticker, "quoteVolume")
	var open any = this.SafeString(ticker, "openPrice")
	var high any = this.SafeString(ticker, "highPrice")
	var low any = this.SafeString(ticker, "lowPrice")
	var prevClose any = this.SafeString(ticker, "prevClosePrice")
	var vwap any = this.SafeString(ticker, "weightedAvgPrice")
	var changeValue any = this.SafeString(ticker, "priceChange")
	var changePcnt any = this.SafeString(ticker, "priceChangePercent")
	changePcnt = Precise.StringMul(changePcnt, "100")
	return this.SafeTicker(map[string]any{
		"symbol":        GetValue(market, "symbol"),
		"timestamp":     timestamp,
		"datetime":      this.Iso8601(timestamp),
		"open":          open,
		"high":          high,
		"low":           low,
		"close":         this.SafeString2(ticker, "lastPrice", "price"),
		"bid":           bid,
		"bidVolume":     bidVolume,
		"ask":           ask,
		"askVolume":     askVolume,
		"vwap":          vwap,
		"previousClose": prevClose,
		"change":        changeValue,
		"percentage":    changePcnt,
		"average":       nil,
		"baseVolume":    baseVolume,
		"quoteVolume":   quoteVolume,
		"info":          ticker,
	}, market)
}

