func (this *CoinsphCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// fetchTrades
	//     {
	//         "price": "89685.8",
	//         "id": "1365561108437680129",
	//         "qty": "0.000004",
	//         "quoteQty": "0.000004000000000000", // warning: report to exchange - this is not quote quantity, this is base quantity
	//         "time": "1677523569575",
	//         "isBuyerMaker": false,
	//         "isBestMatch": true
	//     },
	//
	// fetchMyTrades
	//     {
	//         "symbol": "ETHUSDT",
	//         "id": 1375426310524125185,
	//         "orderId": 1375426310415879614,
	//         "price": "1580.91",
	//         "qty": "0.01",
	//         "quoteQty": "15.8091",
	//         "commission": "0",
	//         "commissionAsset": "USDT",
	//         "time": 1678699593307,
	//         "isBuyer": false,
	//         "isMaker":false,
	//         "isBestMatch":false
	//     }
	//
	// createOrder
	//     {
	//         "price": "1579.51",
	//         "qty": "0.001899",
	//         "commission": "0",
	//         "commissionAsset": "ETH",
	//         "tradeId":1375445992035598337
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString(trade, "symbol")
	market = this.SafeMarket(marketId, market)
	var symbol any = GetValue(market, "symbol")
	var id any = this.SafeString2(trade, "id", "tradeId")
	var orderId any = this.SafeString(trade, "orderId")
	var timestamp any = this.SafeInteger(trade, "time")
	var priceString any = this.SafeString(trade, "price")
	var amountString any = this.SafeString(trade, "qty")
	var typeVar any = nil
	var fee any = nil
	var feeCost any = this.SafeString(trade, "commission")
	if IsTrue(!IsEqual(feeCost, nil)) {
		var feeCurrencyId any = this.SafeString(trade, "commissionAsset")
		fee = map[string]any{
			"cost":     feeCost,
			"currency": this.SafeCurrencyCode(feeCurrencyId),
		}
	}
	var isBuyer any = this.SafeBool2(trade, "isBuyer", "isBuyerMaker", nil)
	var side any = nil
	if IsTrue(!IsEqual(isBuyer, nil)) {
		side = Ternary(IsTrue((IsEqual(isBuyer, true))), "buy", "sell")
	}
	var isMaker any = this.SafeString2(trade, "isMaker", nil)
	var takerOrMaker any = nil
	if IsTrue(!IsEqual(isMaker, nil)) {
		takerOrMaker = Ternary(IsTrue((IsEqual(isMaker, "true"))), "maker", "taker")
	}
	var costString any = nil
	if IsTrue(!IsEqual(orderId, nil)) {
		costString = this.SafeString(trade, "quoteQty")
	}
	return this.SafeTrade(map[string]any{
		"id":           id,
		"order":        orderId,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       symbol,
		"type":         typeVar,
		"side":         side,
		"takerOrMaker": takerOrMaker,
		"price":        priceString,
		"amount":       amountString,
		"cost":         costString,
		"fee":          fee,
		"info":         trade,
	}, market)
}

