func (this *CoinsphCore) ParseOrder(order any, optionalArgs ...any) any {
	//
	// createOrder POST /openapi/v1/order
	//     {
	//         "symbol": "ETHUSDT",
	//         "orderId": 1375445991893797391,
	//         "clientOrderId": "1375445991893799115",
	//         "transactTime": 1678701939513,
	//         "price": "0",
	//         "origQty": "0",
	//         "executedQty": "0.001899",
	//         "cummulativeQuoteQty": "2.99948949",
	//         "status": "FILLED",
	//         "timeInForce": "GTC",
	//         "type": "MARKET",
	//         "side": "BUY",
	//         "stopPrice": "0",
	//         "origQuoteOrderQty": "3",
	//         "fills": [
	//             {
	//                 "price": "1579.51",
	//                 "qty": "0.001899",
	//                 "commission": "0",
	//                 "commissionAsset": "ETH",
	//                 "tradeId":1375445992035598337
	//             }
	//         ]
	//     }
	//
	// fetchOrder GET /openapi/v1/order
	// fetchOpenOrders GET /openapi/v1/openOrders
	// fetchClosedOrders GET /openapi/v1/historyOrders
	// cancelAllOrders DELETE /openapi/v1/openOrders
	//     {
	//         "symbol": "DOGEPHP",
	//         "orderId":1375465375097982423,
	//         "clientOrderId": "1375465375098001241",
	//         "price": "0",
	//         "origQty": "0",
	//         "executedQty": "13",
	//         "cummulativeQuoteQty": "49.621",
	//         "status": "FILLED",
	//         "timeInForce": "GTC",
	//         "type": "MARKET",
	//         "side": "BUY",
	//         "stopPrice": "0",
	//         "time":1678704250171,
	//         "updateTime":1678704250256,
	//         "isWorking":false,
	//         "origQuoteOrderQty": "50"
	//     }
	//
	// cancelOrder DELETE /openapi/v1/order
	//     {
	//         "symbol": "ETHPHP",
	//         "orderId":1375609441915774332,
	//         "clientOrderId": "1375609441915899557",
	//         "price": "96000",
	//         "origQty": "0.001",
	//         "executedQty": "0",
	//         "cummulativeQuoteQty": "0",
	//         "status": "CANCELED",
	//         "timeInForce": "GTC",
	//         "type": "LIMIT",
	//         "side": "SELL",
	//         "stopPrice": "0",
	//         "origQuoteOrderQty": "0"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var id any = this.SafeString(order, "orderId")
	var marketId any = this.SafeString(order, "symbol")
	market = this.SafeMarket(marketId, market)
	var timestamp any = this.SafeInteger2(order, "time", "transactTime")
	var trades any = this.SafeValue(order, "fills", nil)
	var triggerPrice any = this.SafeString(order, "stopPrice")
	if IsTrue(Precise.StringEq(triggerPrice, "0")) {
		triggerPrice = nil
	}
	return this.SafeOrder(map[string]any{
		"id":                 id,
		"clientOrderId":      this.SafeString(order, "clientOrderId"),
		"timestamp":          timestamp,
		"datetime":           this.Iso8601(timestamp),
		"lastTradeTimestamp": nil,
		"status":             this.ParseOrderStatus(this.SafeString(order, "status")),
		"symbol":             GetValue(market, "symbol"),
		"type":               this.ParseOrderType(this.SafeString(order, "type")),
		"timeInForce":        this.ParseOrderTimeInForce(this.SafeString(order, "timeInForce")),
		"side":               this.ParseOrderSide(this.SafeString(order, "side")),
		"price":              this.SafeString(order, "price"),
		"triggerPrice":       triggerPrice,
		"average":            nil,
		"amount":             this.SafeString(order, "origQty"),
		"cost":               this.SafeString(order, "cummulativeQuoteQty"),
		"filled":             this.SafeString(order, "executedQty"),
		"remaining":          nil,
		"fee":                nil,
		"fees":               nil,
		"trades":             trades,
		"info":               order,
	}, market)
}
